export default function Gallery({ section }) {
  const { title, subtitle, cards } = section || {};

  const images = cards?.length > 0 
    ? cards.map(card => ({ src: card.image, alt: card.title }))
    : [
        { src: '/uploads/gallery-1.jpg', alt: 'Project 1' },
        { src: '/uploads/gallery-2.jpg', alt: 'Project 2' },
        { src: '/uploads/gallery-3.jpg', alt: 'Project 3' },
        { src: '/uploads/gallery-4.jpg', alt: 'Project 4' },
      ];

  return (
    <section className="py-16 md:py-20 bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {title && (
          <div className="text-center mb-12">
            <h2 className="text-3xl md:text-4xl font-bold text-gray-900 mb-4">
              {title}
            </h2>
            {subtitle && (
              <p className="text-lg text-gray-600 max-w-2xl mx-auto">{subtitle}</p>
            )}
          </div>
        )}

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {images.map((image, index) => (
            <div 
              key={index} 
              className="aspect-square rounded-xl overflow-hidden bg-gray-200 hover:opacity-90 transition-opacity"
            >
              {image.src ? (
                <img
                  src={image.src}
                  alt={image.alt || `Gallery ${index + 1}`}
                  className="w-full h-full object-cover"
                />
              ) : (
                <div className="w-full h-full flex items-center justify-center text-gray-400">
                  <i className="fas fa-image text-3xl"></i>
                </div>
              )}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
